'use client';

import * as React from 'react';
import { PaykitProvider } from '@paykit-sdk/react';

export const PaykitWrapper = ({
  children,
}: React.PropsWithChildren) => {
  return (
    <PaykitProvider
      headers={{ xApiKey: '1234567890' }}
      apiUrl="/api/paykit"
    >
      {children}
    </PaykitProvider>
  );
};

'use client';

import * as React from 'react';
import {
  useCustomer,
  useSubscription,
  useRefund,
} from '@paykit-sdk/react';

export const CustomerManager = () => {
  const { create: createCustomer } = useCustomer();
  const { create: createSubscription } = useSubscription();
  const { cancel: cancelSubscription } = useSubscription();
  const { create: createRefund } = useRefund();

  const [customerId, setCustomerId] = React.useState<string>();
  const [subscriptionId, setSubscriptionId] =
    React.useState<string>();
  const [paymentId, setPaymentId] = React.useState<string>();

  const handleCreateCustomer = async () => {
    const [data, error] = await createCustomer.run({
      email: 'customer@example.com',
      phone: '+1234567890',
      name: 'John Doe',
      metadata: { source: 'web_app' },
    });

    if (error) {
      console.error('Failed to create customer:', error);
      return;
    }

    setCustomerId(data.id);
  };

  // Create subscription
  const handleCreateSubscription = async () => {
    if (!customerId) return;

    const [data, error] = await createSubscription.run({
      customer: customerId,
      item_id: 'price_...',
      amount: 2999,
      currency: 'USD',
      billing_interval: 'month',
      metadata: { plan: 'pro' },
      quantity: 1,
    });

    if (error) {
      console.error('Failed to create subscription:', error);
      return;
    }

    setSubscriptionId(data.id);
  };

  // Cancel subscription
  const handleCancelSubscription = async () => {
    if (!subscriptionId) return;

    const [, error] = await cancelSubscription.run(subscriptionId);

    if (error) {
      console.error('Failed to cancel subscription:', error);
      return;
    }

    console.log('Subscription cancelled');
  };

  // Create refund
  const handleCreateRefund = async () => {
    if (!paymentId) return;

    const [data, error] = await createRefund.run({
      payment_id: paymentId,
      amount: 1000, // $10.00
      reason: 'customer_request',
      metadata: null,
    });

    if (error) {
      console.error('Failed to create refund:', error);
      return;
    }

    console.log(`Refund created: ${data.id}`);
  };

  return (
    <div className="bg-background flex flex-col gap-4 rounded-lg p-4">
      <h2 className="text-foreground text-2xl font-bold">
        Customer Manager
      </h2>

      {/* Customer Section */}
      <section className="flex flex-col gap-2">
        <h3 className="text-foreground text-lg font-medium">
          Customer
        </h3>
        <button
          onClick={handleCreateCustomer}
          disabled={createCustomer.loading}
        >
          {createCustomer.loading ? 'Creating...' : 'Create Customer'}
        </button>
        {customerId && <p>Customer ID: {customerId}</p>}
      </section>

      {/* Subscription Section */}
      <section className="flex flex-col gap-2">
        <h3 className="text-foreground text-lg font-medium">
          Subscription
        </h3>
        <button
          onClick={handleCreateSubscription}
          disabled={!customerId || createSubscription.loading}
        >
          {createSubscription.loading
            ? 'Creating...'
            : 'Create Subscription'}
        </button>
        <button
          onClick={handleCancelSubscription}
          disabled={!subscriptionId || cancelSubscription.loading}
        >
          {cancelSubscription.loading
            ? 'Cancelling...'
            : 'Cancel Subscription'}
        </button>
        {subscriptionId && <p>Subscription ID: {subscriptionId}</p>}
      </section>

      {/* Refund Section */}
      <section className="flex flex-col gap-2">
        <h3 className="text-foreground text-lg font-medium">
          Refund
        </h3>
        <input
          type="text"
          placeholder="Enter Payment ID"
          value={paymentId}
          onChange={e =>
            setPaymentId(
              (e.target as HTMLInputElement).value as string,
            )
          }
          className="bg-background border-input rounded-md border p-2"
        />

        <button
          onClick={handleCreateRefund}
          disabled={!paymentId || createRefund.loading}
        >
          {createRefund.loading
            ? 'Processing...'
            : 'Create $10 Refund'}
        </button>
      </section>
    </div>
  );
};

'use client';

import * as React from 'react';
import { useCheckout } from '@paykit-sdk/react';

export const CheckoutForm = () => {
  const { create } = useCheckout();
  const [checkoutUrl, setCheckoutUrl] = React.useState<string | null>(
    null,
  );

  const handleCreateCheckout = async () => {
    const [data, error] = await create.run({
      session_type: 'one_time',
      item_id: 'price_123',
      quantity: 1,
      customer: 'cus_z123', // or { email: 'odii@gmail.com' }
      metadata: { source: 'web_app' },
      cancel_url: 'http://localhost:3000/dashboard',
      success_url: 'http://localhost:3000/success',
    });

    if (error) {
      console.error('Checkout creation failed:', error);
      return;
    }

    setCheckoutUrl(data.payment_url);
  };

  return (
    <div className="bg-background flex flex-col gap-4">
      <h2 className="text-foreground text-xl">Proceed to buy</h2>

      <button
        disabled={create.loading}
        onClick={handleCreateCheckout}
        className="bg-primary text-primary-foreground rounded-md px-4 py-2"
      >
        {create.loading ? 'Creating...' : 'Create $29.99 Checkout'}
      </button>

      {checkoutUrl && (
        <div>
          <p>Checkout created!</p>
          <a
            href={checkoutUrl}
            target="_blank"
            rel="noopener noreferrer"
          >
            Go to checkout →
          </a>
        </div>
      )}
    </div>
  );
};

import {
  pgTable,
  text,
  timestamp,
  integer,
  json,
  pgEnum,
  index,
  boolean,
} from 'drizzle-orm/pg-core';

// Enums
export const paymentStatusEnum = pgEnum('payment_status', [
  'pending',
  'processing',
  'requires_action',
  'requires_capture',
  'succeeded',
  'canceled',
  'failed',
]);

export const subscriptionStatusEnum = pgEnum('subscription_status', [
  'active',
  'past_due',
  'canceled',
  'expired',
  'trialing',
  'pending',
]);

export const invoiceStatusEnum = pgEnum('invoice_status', [
  'paid',
  'open',
]);

// Tables
export const customers = pgTable('customers', {
  id: text('id').primaryKey(),
  email: text('email').notNull().unique(),
  name: text('name').notNull(),
  phone: text('phone'),
  metadata: json('metadata'),
  createdAt: timestamp('created_at').defaultNow().notNull(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
});

export const payments = pgTable(
  'payments',
  {
    id: text('id').primaryKey(),
    amount: integer('amount').notNull(),
    currency: text('currency').notNull(),
    status: paymentStatusEnum('status').notNull(),
    itemId: text('item_id'),
    metadata: json('metadata').notNull(),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),

    // Optional customer relationship
    customerId: text('customer_id').references(() => customers.id, {
      onDelete: 'cascade',
    }),

    // Guest checkout for when the customer is not yet determined
    customerEmail: text('customer_email'),

    paymentUrl: text('payment_url'),
    requiresAction: boolean('requires_action').default(false),
  },
  table => ({
    customerIdIdx: index('payments_customer_id_idx').on(
      table.customerId,
    ),
    statusIdx: index('payments_status_idx').on(table.status),
    customerEmailIdx: index('payments_customer_email_idx').on(
      table.customerEmail,
    ),
  }),
);

export const subscriptions = pgTable(
  'subscriptions',
  {
    id: text('id').primaryKey(),
    amount: integer('amount').notNull(),
    currency: text('currency').notNull(),
    status: subscriptionStatusEnum('status').notNull(),
    itemId: text('item_id').notNull(),
    billingInterval: text('billing_interval').notNull(),
    currentPeriodStart: timestamp('current_period_start').notNull(),
    currentPeriodEnd: timestamp('current_period_end').notNull(),
    metadata: json('metadata'),
    customFields: json('custom_fields'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),

    // Optional customer relationship
    customerId: text('customer_id').references(() => customers.id, {
      onDelete: 'cascade',
    }),

    // Guest checkout for when the customer is not yet determined
    customerEmail: text('customer_email'),
  },
  table => ({
    customerIdIdx: index('subscriptions_customer_id_idx').on(
      table.customerId,
    ),
    statusIdx: index('subscriptions_status_idx').on(table.status),
    customerEmailIdx: index('subscriptions_customer_email_idx').on(
      table.customerEmail,
    ),
  }),
);

export const refunds = pgTable(
  'refunds',
  {
    id: text('id').primaryKey(),
    amount: integer('amount').notNull(),
    currency: text('currency').notNull(),
    reason: text('reason'),
    metadata: json('metadata'),
    createdAt: timestamp('created_at').defaultNow().notNull(),

    paymentId: text('payment_id')
      .notNull()
      .references(() => payments.id, { onDelete: 'cascade' }),
  },
  table => ({
    paymentIdIdx: index('refunds_payment_id_idx').on(table.paymentId),
  }),
);

export const invoices = pgTable(
  'invoices',
  {
    id: text('id').primaryKey(),
    subscriptionId: text('subscription_id').references(
      () => subscriptions.id,
      {
        onDelete: 'set null',
      },
    ),
    billingMode: text('billing_mode').notNull(),
    amountPaid: integer('amount_paid').notNull(),
    currency: text('currency').notNull(),
    status: invoiceStatusEnum('status').notNull(),
    paidAt: timestamp('paid_at'),
    lineItems: json('line_items'),
    metadata: json('metadata'),
    customFields: json('custom_fields'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),

    customerId: text('customer_id').references(() => customers.id, {
      onDelete: 'cascade',
    }),

    // Guest checkout for when the customer is not yet determined
    customerEmail: text('customer_email'),
  },
  table => ({
    customerIdIdx: index('invoices_customer_id_idx').on(
      table.customerId,
    ),
    subscriptionIdIdx: index('invoices_subscription_id_idx').on(
      table.subscriptionId,
    ),
    statusIdx: index('invoices_status_idx').on(table.status),
    customerEmailIdx: index('invoices_customer_email_idx').on(
      table.customerEmail,
    ),
  }),
);

export type Invoice = typeof invoices.$inferSelect;
export type Customer = typeof customers.$inferSelect;
export type Payment = typeof payments.$inferSelect;
export type Subscription = typeof subscriptions.$inferSelect;
export type Refund = typeof refunds.$inferSelect;

import {
    Entity,
    PrimaryColumn,
    Column,
    CreateDateColumn,
    UpdateDateColumn,
    ManyToOne,
    JoinColumn,
    Index,
  } from 'typeorm';

  // Enums
  export enum PaymentStatus {
    PENDING = 'pending',
    PROCESSING = 'processing',
    REQUIRES_ACTION = 'requires_action',
    REQUIRES_CAPTURE = 'requires_capture',
    SUCCEEDED = 'succeeded',
    CANCELED = 'canceled',
    FAILED = 'failed',
  }

  export enum SubscriptionStatus {
    ACTIVE = 'active',
    PAST_DUE = 'past_due',
    CANCELED = 'canceled',
    EXPIRED = 'expired',
    TRIALING = 'trialing',
    PENDING = 'pending',
  }

  export enum InvoiceStatus {
    PAID = 'paid',
    OPEN = 'open',
  }

  // Entities
  @Entity('customers')
  export class Customer {
    @PrimaryColumn({ type: 'text' })
    id!: string;

  @Column({ type: 'text', unique: true })
  @Index()
  email!: string;

  @Column({ type: 'text' })
  name!: string;

  @Column({ type: 'text' })
  phone!: string;

  @Column({ type: 'jsonb', nullable: true })
  metadata?: Record<string, any>;

  @CreateDateColumn({ type: 'timestamp', name: 'created_at' })
  createdAt!: Date;

  @UpdateDateColumn({ type: 'timestamp', name: 'updated_at' })
  updatedAt!: Date;
}

  @Entity('payments')
  export class Payment {
    @PrimaryColumn({ type: 'text' })
    id!: string;

    @Column({ type: 'integer' })
    amount!: number;

    @Column({ type: 'text' })
    currency!: string;

    @Column({
      type: 'enum',
      enum: PaymentStatus,
    })
    @Index()
    status!: PaymentStatus;

    @Column({ type: 'text', nullable: true, name: 'item_id' })
    itemId?: string;

    @Column({ type: 'jsonb' })
    metadata!: Record<string, any>;

    @Column({ type: 'text', nullable: true, name: 'customer_id' })
    @Index()
    customerId?: string;

    @ManyToOne(() => Customer, { onDelete: 'CASCADE' })
    @JoinColumn({ name: 'customer_id' })
    customer?: Customer;

    @Column({ type: 'text', nullable: true, name: 'customer_email' })
    @Index()
    customerEmail?: string;

    @Column({ type: 'text', nullable: true, name: 'payment_url' })
    paymentUrl?: string;

    @Column({ type: 'boolean', nullable: true, name: 'requires_action' })
    requiresAction?: boolean;

    @CreateDateColumn({ type: 'timestamp', name: 'created_at' })
    createdAt!: Date;

    @UpdateDateColumn({ type: 'timestamp', name: 'updated_at' })
    updatedAt!: Date;
  }

 @Entity('subscriptions')
 export class Subscription {
  @PrimaryColumn({ type: 'text' })
  id!: string;

    @Column({ type: 'integer' })
    amount!: number;

    @Column({ type: 'text' })
    currency!: string;

    @Column({
      type: 'enum',
      enum: SubscriptionStatus,
    })
    @Index()
    status!: SubscriptionStatus;

    @Column({ type: 'text', name: 'item_id' })
    itemId!: string;

    @Column({ type: 'text', name: 'billing_interval' })
    billingInterval!: string;

    @Column({ type: 'timestamp', name: 'current_period_start' })
    currentPeriodStart!: Date;

    @Column({ type: 'timestamp', name: 'current_period_end' })
    currentPeriodEnd!: Date;

    @Column({ type: 'jsonb', nullable: true })
    metadata?: Record<string, any>;

    @Column({ type: 'jsonb', nullable: true, name: 'custom_fields' })
    customFields?: Record<string, any>;

    @Column({ type: 'text', nullable: true, name: 'customer_id' })
    @Index()
    customerId?: string;

    @ManyToOne(() => Customer, { onDelete: 'CASCADE' })
    @JoinColumn({ name: 'customer_id' })
    customer?: Customer;

    @Column({ type: 'text', nullable: true, name: 'customer_email' })
    @Index()
    customerEmail?: string;

  @CreateDateColumn({ type: 'timestamp', name: 'created_at' })
  createdAt!: Date;

  @UpdateDateColumn({ type: 'timestamp', name: 'updated_at' })
  updatedAt!: Date;
}

  @Entity('refunds')
  export class Refund {
    @PrimaryColumn({ type: 'text' })
    id!: string;

    @Column({ type: 'integer' })
    amount!: number;

    @Column({ type: 'text' })
    currency!: string;

    @Column({ type: 'text', nullable: true })
    reason?: string;

    @Column({ type: 'jsonb', nullable: true })
    metadata?: Record<string, any>;

    @Column({ type: 'text', name: 'payment_id' })
    @Index()
    paymentId!: string;

    @ManyToOne(() => Payment, { onDelete: 'CASCADE' })
    @JoinColumn({ name: 'payment_id' })
    payment!: Payment;

    @CreateDateColumn({ type: 'timestamp', name: 'created_at' })
    createdAt!: Date;
  }

  @Entity('invoices')
  export class Invoice {
    @PrimaryColumn({ type: 'text' })
    id!: string;

    @Column({ type: 'text', nullable: true, name: 'subscription_id' })
    @Index()
    subscriptionId?: string;

    @ManyToOne(() => Subscription, { onDelete: 'SET NULL' })
    @JoinColumn({ name: 'subscription_id' })
    subscription?: Subscription;

    @Column({ type: 'text', name: 'billing_mode' })
    billingMode!: string;

  @Column({ type: 'integer', name: 'amount_paid' })
  amountPaid!: number;

  @Column({ type: 'text' })
  currency!: string;

