          'succeeded',
          'canceled',
          'failed',
        ),
        allowNull: false,
      },
      itemId: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'item_id',
      },
      metadata: {
        type: DataTypes.JSONB,
        allowNull: false,
      },
      customerId: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_id',
        references: {
          model: 'customers',
          key: 'id',
        },
        onDelete: 'CASCADE',
      },
      customerEmail: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_email',
      },
      paymentUrl: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'payment_url',
      },
      requiresAction: {
        type: DataTypes.BOOLEAN,
        allowNull: true,
        field: 'requires_action',
        defaultValue: false,
      },
    },
    {
      sequelize,
      tableName: 'payments',
      timestamps: true,
      underscored: true,
      indexes: [
        { fields: ['customer_id'] },
        { fields: ['status'] },
        { fields: ['customer_email'] },
      ],
    },
  );

  // Subscription Model
  class Subscription extends Model {
    declare id: string;
    declare amount: number;
    declare currency: string;
    declare status: string;
    declare itemId: string;
    declare billingInterval: string;
    declare currentPeriodStart: Date;
    declare currentPeriodEnd: Date;
    declare metadata?: Record<string, any>;
    declare customFields?: Record<string, any>;
    declare customerId?: string;
    declare customerEmail?: string;
    declare createdAt: Date;
    declare updatedAt: Date;
  }

  Subscription.init(
    {
      id: {
        type: DataTypes.STRING,
        primaryKey: true,
      },
      amount: {
        type: DataTypes.INTEGER,
        allowNull: false,
      },
      currency: {
        type: DataTypes.STRING,
        allowNull: false,
      },
      status: {
        type: DataTypes.ENUM(
          'active',
          'past_due',
          'canceled',
          'expired',
          'trialing',
          'pending',
        ),
        allowNull: false,
      },
      itemId: {
        type: DataTypes.STRING,
        allowNull: false,
        field: 'item_id',
      },
      billingInterval: {
        type: DataTypes.STRING,
        allowNull: false,
        field: 'billing_interval',
      },
      currentPeriodStart: {
        type: DataTypes.DATE,
        allowNull: false,
        field: 'current_period_start',
      },
      currentPeriodEnd: {
        type: DataTypes.DATE,
        allowNull: false,
        field: 'current_period_end',
      },
      metadata: {
        type: DataTypes.JSONB,
        allowNull: true,
      },
      customFields: {
        type: DataTypes.JSONB,
        allowNull: true,
        field: 'custom_fields',
      },
      customerId: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_id',
        references: {
          model: 'customers',
          key: 'id',
        },
        onDelete: 'CASCADE',
      },
      customerEmail: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_email',
      },
    },
    {
      sequelize,
      tableName: 'subscriptions',
      timestamps: true,
      underscored: true,
      indexes: [
        { fields: ['customer_id'] },
        { fields: ['status'] },
        { fields: ['customer_email'] },
      ],
    },
  );

  // Refund Model
  class Refund extends Model {
    declare id: string;
    declare amount: number;
    declare currency: string;
    declare reason?: string;
    declare metadata?: Record<string, any>;
    declare paymentId: string;
    declare createdAt: Date;
