  Refund.init(
    {
      id: {
        type: DataTypes.STRING,
        primaryKey: true,
      },
      amount: {
        type: DataTypes.INTEGER,
        allowNull: false,
      },
      currency: {
        type: DataTypes.STRING,
        allowNull: false,
      },
      reason: {
        type: DataTypes.STRING,
        allowNull: true,
      },
      metadata: {
        type: DataTypes.JSONB,
        allowNull: true,
      },
      paymentId: {
        type: DataTypes.STRING,
        allowNull: false,
        field: 'payment_id',
        references: {
          model: 'payments',
          key: 'id',
        },
        onDelete: 'CASCADE',
      },
    },
    {
      sequelize,
      tableName: 'refunds',
      timestamps: false,
      underscored: true,
      indexes: [{ fields: ['payment_id'] }],
