      },
      paidAt: {
        type: DataTypes.DATE,
        allowNull: true,
        field: 'paid_at',
      },
      lineItems: {
        type: DataTypes.JSONB,
        allowNull: true,
        field: 'line_items',
      },
      metadata: {
        type: DataTypes.JSONB,
        allowNull: true,
      },
      customFields: {
        type: DataTypes.JSONB,
        allowNull: true,
        field: 'custom_fields',
      },
      customerId: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_id',
        references: {
          model: 'customers',
          key: 'id',
        },
        onDelete: 'CASCADE',
      },
      customerEmail: {
        type: DataTypes.STRING,
        allowNull: true,
        field: 'customer_email',
      },
    },
    {
      sequelize,
      tableName: 'invoices',
      timestamps: true,
      underscored: true,
      indexes: [
        { fields: ['customer_id'] },
        { fields: ['subscription_id'] },
        { fields: ['status'] },
        { fields: ['customer_email'] },
      ],
    },
  );

  // Define associations
  Customer.hasMany(Payment, {
    foreignKey: 'customerId',
    onDelete: 'CASCADE',
  });
  Payment.belongsTo(Customer, { foreignKey: 'customerId' });

  Customer.hasMany(Subscription, {
    foreignKey: 'customerId',
    onDelete: 'CASCADE',
  });
  Subscription.belongsTo(Customer, { foreignKey: 'customerId' });

  Payment.hasMany(Refund, {
    foreignKey: 'paymentId',
    onDelete: 'CASCADE',
  });
  Refund.belongsTo(Payment, { foreignKey: 'paymentId' });

  Customer.hasMany(Invoice, {
    foreignKey: 'customerId',
    onDelete: 'CASCADE',
  });
  Invoice.belongsTo(Customer, { foreignKey: 'customerId' });

  Subscription.hasMany(Invoice, {
    foreignKey: 'subscriptionId',
    onDelete: 'SET NULL',
  });
  Invoice.belongsTo(Subscription, { foreignKey: 'subscriptionId' });

  return {
    Customer,
    Payment,
    Subscription,
    Refund,
    Invoice,
  };
};

